def get_mean_std(delta_dict):
    mat = np.array([delta_dict[s] for s in seeds])
    return mat.mean(axis=0), mat.std(axis=0)

k1_mean, k1_std = get_mean_std(k1_deltas)
k2_mean, k2_std = get_mean_std(k2_deltas)
k3_mean, k3_std = get_mean_std(k3_deltas)

fig, ax = plt.subplots(figsize=(10, 5))

colors = {'k1': '#534AB7', 'k2': '#D85A30', 'k3': '#1D9E75'}

ax.plot(steps, k1_mean, color=colors['k1'], linewidth=2, label='k=1 (1 spurious feature)')
ax.fill_between(steps, k1_mean-k1_std, k1_mean+k1_std, alpha=0.15, color=colors['k1'])

ax.plot(steps, k2_mean, color=colors['k2'], linewidth=2, label='k=2 (2 spurious features)')
ax.fill_between(steps, k2_mean-k2_std, k2_mean+k2_std, alpha=0.15, color=colors['k2'])

ax.plot(steps, k3_mean, color=colors['k3'], linewidth=2, label='k=3 (3 spurious features)')
ax.fill_between(steps, k3_mean-k3_std, k3_mean+k3_std, alpha=0.15, color=colors['k3'])

ax.axhline(y=0, color='black', linestyle='--', alpha=0.4)
ax.set_xlabel('Training steps', fontsize=12)
ax.set_ylabel('Shortcut gap δ(t) = Train − Test', fontsize=12)
ax.set_title('Shortcut gap δ(t) by number of spurious features (mean ± std, 3 seeds)', fontsize=12)
ax.legend(fontsize=11)
ax.grid(True, alpha=0.3)

plt.tight_layout()
os.makedirs('results/figures', exist_ok=True)
plt.savefig('results/figures/k_comparison_delta.png', dpi=150)
plt.show()
plt.close()
print("Saved k comparison plot.")